module RefModule (
    input [7:0] numerator,
    input [7:0] denominator,
    input start,
    input clk,
    input reset,
    output reg [7:0] quotient,
    output reg [7:0] remainder,
    output reg ready
);
    reg [7:0] num, denom;
    reg [3:0] count;
    reg pipeline_reg;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            quotient <= 0;
            remainder <= 0;
            ready <= 0;
            count <= 0;
            pipeline_reg <= 0;
        end else if (start && !pipeline_reg) begin
            num <= numerator;
            denom <= denominator;
            quotient <= 0;
            remainder <= 0;
            count <= 0;
            pipeline_reg <= 1;
        end else if (pipeline_reg) begin
            if (count < 8) begin
                remainder = {remainder[6:0], num[7]};
                num = {num[6:0], 1'b0};
                if (remainder >= denom) begin
                    remainder = remainder - denom;
                    quotient = quotient | (1'b1 << (7 - count));
                end
                count <= count + 1;
            end else begin
                ready <= 1;
                pipeline_reg <= 0;
            end
        end
    end
endmodule
